steps.script:
var built = RulesEngine._build_attached_allocation_unit_11e("U_BOYZ_F", GameState.state)
var pref = CasualtyPreference.compute_preferred_targets(built.unit, GameState.state, {"defender_player": 2})
GameState.state.meta["_test_expected_casualties"] = pref.slice(0, 4)
var models = GameState.get_unit("U_BOYZ_F").models
var meas = node.get_node("/root/Measurement")
var enemies = []
for uid in GameState.state.units:
	var u = GameState.state.units[uid]
	if int(u.get("owner", 0)) == 1:
		for em in u.get("models", []):
			if em.get("alive", true) and em.get("position") != null:
				enemies.append(em)
var far_i = -1
var far_d = -1.0
for i in range(models.size()):
	if not models[i].get("alive", true) or models[i].get("position") == null:
		continue
	var best = INF
	for em in enemies:
		best = min(best, meas.model_to_model_distance_inches(models[i], em))
	if best > far_d:
		far_d = best
		far_i = i
GameState.state.meta["_test_farthest_model"] = far_i
var alive_virtual = 0
for m in built.unit.models:
	if m.get("alive", true):
		alive_virtual += 1
return "ORDERED_ALL" if pref.size() == alive_virtual and alive_virtual >= 20 else "pref=%d alive=%d" % [pref.size(), alive_virtual]

var expected = GameState.state.meta.get("_test_expected_casualties", [])
var models = GameState.get_unit("U_BOYZ_F").models
var dead = []
for i in range(models.size()):
	if not models[i].get("alive", true):
		dead.append(i)
dead.sort()
var exp = []
for v in expected:
	exp.append(int(v))
exp.sort()
return str(dead) + " vs expected " + str(exp) if str(dead) != str(exp) else "MATCH"

var far_i = int(GameState.state.meta.get("_test_farthest_model", -1))
var models = GameState.get_unit("U_BOYZ_F").models
return far_i >= 0 and models[far_i].get("alive", true)
